  // Get gitLabworkflow
  const contentJSON = $('Get backup workflow').first().json;

  const gitLabWorkFlowLastUpdate = contentJSON.updatedAt;

  if ( gitLabWorkFlowLastUpdate === n8nWorkflowLastUpdate) {
    $input.all()[0].json.gitlab_status = "same";
  } else {
    // there is an update
    $input.all()[0].json.gitlab_status = "update";
  }
} else {
  // Create new file on gitlab
  $input.all()[0].json.gitlab_status = "new";
}

// add last update date
$('Execute Workflow Trigger').first().json.lastUpdate = n8nWorkflowLastUpdate;

